arguments.argument:
if global.gamePaused=false
{
  makeEnemyActive(0)
  if bActive=true and stunnedTime=0
  {
    dirChange+=1
    if dirChange>=60
    {
      if xVel>0
        xVel-=runAcc/30
      else
        xVel+=runAcc/30
      if dirChange>=87
      {
        if xVel>0
          xVel=-runAcc
        else
          xVel=runAcc
        dirChange=0
      }
    }
    if isCollisionLeft(1)
      xVel*=-1
    if isCollisionRight(1)
      xVel*=-1
    
    if xVel>0
      image_xscale=1
    else
      image_xscale=-1
    moveTo(xVel,yVel)
    if isCollisionSolid()
      y-=2
  }
  enemyStepEvent()
}
